"use client";

import React, {
  createContext,
  useContext,
  useEffect,
  useState,
} from "react";

export type Role = "user" | "admin";

export type User = {
  name: string;
  email: string;
  role: Role;
} | null;

export type Profile = {
  firstName: string;
  middleName?: string;
  lastName?: string;
  dob?: string;
  gender?: string;
  maritalStatus?: string;
  addressLine1?: string;
  addressLine2?: string;
  city?: string;
  state?: string;
  pincode?: string;
  country?: string;
} | null;

type LoginInput = {
  email: string;
  password: string;
  role: Role;
};

type SignupInput = {
  name: string;
  email: string;
  password: string;
};

type StoredUser = {
  name: string;
  email: string;
  passwordHash: string;
  role: Role;
  profile: Profile;
};

type AuthContextType = {
  user: User;
  profile: Profile;
  isLoading: boolean;
  updateProfile: (data: NonNullable<Profile>) => void;
  login: (input: LoginInput) => Promise<void>;
  signup: (input: SignupInput) => Promise<void>;
  logout: () => void;
};

const USERS_STORAGE_KEY = "fmc_users";
const SESSION_STORAGE_KEY = "fmc_session_user";
const AUTH_COOKIE_KEY = "fmc_auth";
const ROLE_COOKIE_KEY = "fmc_role";

const DEMO_ADMIN = {
  name: "City Admin",
  email: "admin@fixmycity.com",
  password: "Admin@123",
  role: "admin" as const,
};

const AuthContext = createContext<AuthContextType | undefined>(undefined);

function normalizeEmail(email: string) {
  return email.trim().toLowerCase();
}

async function hashPassword(password: string) {
  const data = new TextEncoder().encode(password);
  const hashBuffer = await window.crypto.subtle.digest("SHA-256", data);
  return Array.from(new Uint8Array(hashBuffer))
    .map((byte) => byte.toString(16).padStart(2, "0"))
    .join("");
}

function readStoredUsers(): StoredUser[] {
  if (typeof window === "undefined") return [];

  try {
    const raw = window.localStorage.getItem(USERS_STORAGE_KEY);
    if (!raw) return [];
    const parsed = JSON.parse(raw);
    return Array.isArray(parsed) ? parsed : [];
  } catch {
    return [];
  }
}

function writeStoredUsers(users: StoredUser[]) {
  window.localStorage.setItem(USERS_STORAGE_KEY, JSON.stringify(users));
}

function persistSession(nextUser: NonNullable<User>) {
  window.localStorage.setItem(SESSION_STORAGE_KEY, JSON.stringify(nextUser));
  document.cookie = `${AUTH_COOKIE_KEY}=1; path=/; max-age=${60 * 60 * 24 * 7}; SameSite=Lax`;
  document.cookie = `${ROLE_COOKIE_KEY}=${nextUser.role}; path=/; max-age=${60 * 60 * 24 * 7}; SameSite=Lax`;
}

function clearSession() {
  window.localStorage.removeItem(SESSION_STORAGE_KEY);
  document.cookie = `${AUTH_COOKIE_KEY}=; path=/; max-age=0; SameSite=Lax`;
  document.cookie = `${ROLE_COOKIE_KEY}=; path=/; max-age=0; SameSite=Lax`;
}

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [user, setUser] = useState<User>(null);
  const [profile, setProfile] = useState<Profile>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    let active = true;

    const bootstrapAuth = async () => {
      if (typeof window === "undefined") return;

      const users = readStoredUsers();
      const adminEmail = normalizeEmail(DEMO_ADMIN.email);
      const hasAdmin = users.some((storedUser) => storedUser.email === adminEmail);

      if (!hasAdmin) {
        users.push({
          name: DEMO_ADMIN.name,
          email: adminEmail,
          passwordHash: await hashPassword(DEMO_ADMIN.password),
          role: DEMO_ADMIN.role,
          profile: {
            firstName: "City",
            lastName: "Admin",
            city: "Demo City",
            state: "Admin State",
            country: "India",
          },
        });
        writeStoredUsers(users);
      }

      let nextUser: User = null;

      try {
        const savedSession = window.localStorage.getItem(SESSION_STORAGE_KEY);
        if (savedSession) {
          const parsedSession = JSON.parse(savedSession) as NonNullable<User>;
          const storedUser = readStoredUsers().find(
            (entry) => entry.email === normalizeEmail(parsedSession.email),
          );

          if (storedUser) {
            nextUser = {
              name: storedUser.name,
              email: storedUser.email,
              role: storedUser.role,
            };
          } else {
            clearSession();
          }
        }
      } catch {
        clearSession();
      }

      if (!active) return;

      setUser(nextUser);
      setProfile(
        nextUser
          ? readStoredUsers().find((entry) => entry.email === nextUser?.email)?.profile ?? null
          : null,
      );
      setIsLoading(false);
    };

    bootstrapAuth();

    return () => {
      active = false;
    };
  }, []);

  const updateProfile = (data: NonNullable<Profile>) => {
    if (!user || typeof window === "undefined") return;

    const users = readStoredUsers().map((entry) =>
      entry.email === user.email ? { ...entry, profile: data } : entry,
    );

    writeStoredUsers(users);
    setProfile(data);
  };

  const login = async ({ email, password, role }: LoginInput) => {
    const normalizedEmail = normalizeEmail(email);
    const users = readStoredUsers();
    const matchedUser = users.find((entry) => entry.email === normalizedEmail);

    if (!matchedUser) {
      throw new Error("No account found with this email.");
    }

    if (matchedUser.role !== role) {
      throw new Error(
        role === "admin"
          ? "This account does not have admin access."
          : "Please choose the correct login type for this account.",
      );
    }

    const passwordHash = await hashPassword(password);
    if (matchedUser.passwordHash !== passwordHash) {
      throw new Error("Incorrect password.");
    }

    const nextUser = {
      name: matchedUser.name,
      email: matchedUser.email,
      role: matchedUser.role,
    } satisfies NonNullable<User>;

    persistSession(nextUser);
    setUser(nextUser);
    setProfile(matchedUser.profile ?? null);
  };

  const signup = async ({ name, email, password }: SignupInput) => {
    const trimmedName = name.trim();
    const normalizedEmail = normalizeEmail(email);
    const users = readStoredUsers();

    if (users.some((entry) => entry.email === normalizedEmail)) {
      throw new Error("An account with this email already exists.");
    }

    const nextStoredUser: StoredUser = {
      name: trimmedName,
      email: normalizedEmail,
      passwordHash: await hashPassword(password),
      role: "user",
      profile: {
        firstName: trimmedName,
      },
    };

    writeStoredUsers([...users, nextStoredUser]);

    const nextUser = {
      name: nextStoredUser.name,
      email: nextStoredUser.email,
      role: nextStoredUser.role,
    } satisfies NonNullable<User>;

    persistSession(nextUser);
    setUser(nextUser);
    setProfile(nextStoredUser.profile);
  };

  const logout = () => {
    if (typeof window !== "undefined") {
      clearSession();
    }

    setUser(null);
    setProfile(null);
  };

  return (
    <AuthContext.Provider
      value={{ user, profile, isLoading, updateProfile, login, signup, logout }}
    >
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const ctx = useContext(AuthContext);
  if (!ctx) {
    throw new Error("useAuth must be used inside AuthProvider");
  }
  return ctx;
}
